import React, { useEffect } from 'react';
import { Link } from 'gatsby';

const Pagination = ({ currentPage, numberOfPages }) => {
  const isFirst = currentPage === 1;
  const isLast = currentPage === numberOfPages;

  useEffect(() => {
    if (typeof window !== 'undefined') {
      // Clear localStorage items if they exist
      if (localStorage.getItem('selectedCategory') || localStorage.getItem('loadMoreCount')) {
        localStorage.removeItem('selectedCategory');
        localStorage.removeItem('loadMoreCount');
      }
    }
  }, []);

  // Update to use /page/ for pages after the first
  const nextPage = currentPage - 1 === 1 ? "/blog" : `/page/${currentPage - 1}`;
  const prevPage = `/page/${currentPage + 1}`;

  return (
    <div className="pagination">
        {!isLast ? (
          <Link to={prevPage} className="prev" rel="prev">
            Previous
          </Link>
        ) : (
          <span className="prev text-gray-300">
            Previous
          </span>
        )}
        {!isFirst ? (
          <Link to={nextPage} className="next" rel="next">
            Next
          </Link>
        ) : (
          <span className="next text-gray-300">
            Next
          </span>
        )}

    </div>
  );
};

export default Pagination;
